private async load(): Promise<void> {
  const id = this.id();
  const version = ++this.loadVersion;

  this.loading.set(true);
  try {
    const lookupsPromise = this.service.getLookups();

    if (id && GUID_REGEX.test(id)) {
      const [aggregate, lookups] = await Promise.all([
        this.service.get(id),
        lookupsPromise,
      ]);
      if (version !== this.loadVersion) return;

      this.lookups.set(lookups);
      this.aggregate.set(aggregate);
      this.childRows.set(stitchChildRows(aggregate, lookups));
      this.captureInitialState();
      return;
    }

    const lookups = await lookupsPromise;
    this.lookups.set(lookups);
    this.aggregate.set(createDraftAggregate(lookups));
    this.captureInitialState();
  } finally {
    if (version === this.loadVersion) this.loading.set(false);
  }
}

