import { ChangeDetectionStrategy, Component, computed, effect, inject, input, signal } from '@angular/core';
import { DatePipe } from '@angular/common';
import { Router, RouterLink, RouterOutlet } from '@angular/router';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { ToastrService } from 'ngx-toastr';
import {
  TextFieldComponent,
  DropdownFieldComponent,
  CapturePageTitleComponent,
  ConfirmationDialogService,
} from '@nxgn-solutions/ui';

import { ActionDTO, ActionEvidenceDTO, SaveActionRequest } from './action.models';
import { ActionService } from './action.service';
import { ActionCaptureState } from './action-capture.state';
import { ActionEvidenceListComponent } from './action-evidence-list.component';

const EMPTY_GUID = '00000000-0000-0000-0000-000000000000';
const GUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const SLUG_REGEX = /^[a-z][a-z0-9._-]*$/;

@Component({
  selector: 'app-action-capture',
  standalone: true,
  imports: [
    DatePipe,
    TranslatePipe,
    RouterLink,
    RouterOutlet,
    TextFieldComponent,
    CapturePageTitleComponent,
    ActionEvidenceListComponent,
  ],
  providers: [ActionCaptureState],  // Only if entity has child routes
  templateUrl: './action-capture.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ActionCaptureComponent {
  private readonly router = inject(Router);
  private readonly toastr = inject(ToastrService);
  private readonly translate = inject(TranslateService);
  private readonly actionService = inject(ActionService);
  private readonly confirmService = inject(ConfirmationDialogService);
  private readonly state = inject(ActionCaptureState);  // Only if entity has child routes

  // --- Route param ---

  /** Bound from route param `:id` via withComponentInputBinding() */
  id = input<string>();

  isEditMode = computed(() => {
    const idVal = this.id();
    return !!idVal && GUID_REGEX.test(idVal);
  });

  // --- State ---

  loading = signal(false);
  saving = signal(false);
  errorMessage = signal('');
  action = signal<ActionDTO | null>(null);

  // --- Form fields ---

  name = signal('');
  slug = signal('');
  slugManuallyEdited = signal(false);

  // --- Aggregate children (delegated to state for child route access) ---

  evidence = this.state.evidence;

  /** Track server-assigned IDs to distinguish new vs existing items on save */
  private serverEvidenceIds = new Set<string>();

  /** Whether a child route (evidence capture) is active */
  childActive = signal(false);

  // --- Duplicate detection ---

  /** Unique names loaded from server, excluding current entity in edit mode */
  private uniqueNames = signal<string[]>([]);

  // --- Validation ---

  nameErrors = computed(() => {
    const n = this.name().trim();
    const errors: string[] = [];
    if (n.length > 255) errors.push(this.t('validation_name_max_length'));
    if (n && this.uniqueNames().some(u => u.toLowerCase() === n.toLowerCase())) {
      errors.push(this.t('validation_name_duplicate'));
    }
    return errors;
  });

  slugErrors = computed(() => {
    const s = this.slug().trim();
    const errors: string[] = [];
    if (s.length > 0 && !SLUG_REGEX.test(s)) {
      errors.push(this.t('validation_slug_pattern'));
    }
    if (s.length > 100) errors.push(this.t('validation_slug_max_length'));
    return errors;
  });

  isFormValid = computed(() => {
    if (this.saving() || this.loading()) return false;
    const n = this.name().trim();
    if (!n || n.length > 255) return false;
    if (this.nameErrors().length > 0) return false;
    const s = this.slug().trim();
    if (!s || s.length > 100 || !SLUG_REGEX.test(s)) return false;
    return true;
  });

  // --- System entity guard ---

  get isProtected(): boolean {
    const a = this.action();
    return !!a && a.isCore;
  }

  // --- Translation helper ---

  /** Synchronous translation — safe inside computed() */
  private t(key: string, params?: Record<string, unknown>): string {
    return this.translate.instant(key, params);
  }

  // --- Effects ---

  constructor() {
    // Load entity when route param changes to a valid GUID
    effect(() => {
      const idVal = this.id();
      if (idVal && GUID_REGEX.test(idVal)) {
        this.loadAction(idVal);
      }
    });

    // Auto-generate slug from name in create mode only
    effect(() => {
      const n = this.name();
      if (this.isEditMode() || this.slugManuallyEdited()) return;
      this.slug.set(this.generateSlug(n));
    });
  }

  // --- Slug input ---

  /** One-way binding + explicit handler to track manual edits */
  onSlugInput(value: string): void {
    this.slugManuallyEdited.set(true);
    this.slug.set(value);
  }

  // --- Load ---

  private async loadAction(id: string): Promise<void> {
    this.loading.set(true);
    this.errorMessage.set('');

    try {
      // 1. Fetch the aggregate DTO
      const dto = await this.actionService.get(id);
      this.action.set(dto);

      // 2. Populate form signals from DTO
      this.name.set(dto.name);
      this.slug.set(dto.slug);

      // 3. Populate aggregate children in state (for child route access)
      this.evidence.set(dto.evidence);
      this.state.actionId.set(dto.id);

      // 4. Snapshot server IDs for child diffing on save
      this.serverEvidenceIds = new Set(dto.evidence.map(c => c.id));

      // 5. Load secondary data in parallel
      await this.loadSecondaryData(dto);
    } catch {
      this.errorMessage.set(await firstValueFrom(this.translate.get('common_load_error')));
    } finally {
      this.loading.set(false);
    }
  }

  private async loadSecondaryData(dto: ActionDTO): Promise<void> {
    const [uniqueNames, complianceProfileOptions] = await Promise.all([
      this.actionService.getUniqueNames(dto.id),
      this.actionService.getComplianceProfileOptions(dto.slug),
    ]);
    this.uniqueNames.set(uniqueNames);
    this.state.complianceProfileOptions.set(complianceProfileOptions);
  }

  // --- Save ---

  async onSave(): Promise<void> {
    if (!this.isFormValid()) return;

    this.saving.set(true);
    this.errorMessage.set('');

    try {
      // 1. Diff children: new items get EMPTY_GUID, existing keep server ID
      const evidence = this.evidence().map(c => ({
        ...c,
        id: this.serverEvidenceIds.has(c.id) ? c.id : EMPTY_GUID,
      }));

      // 2. Build the save request
      const request: SaveActionRequest = {
        id: this.isEditMode() ? this.id()! : EMPTY_GUID,
        name: this.name().trim(),
        slug: this.slug().trim(),
        evidence,
      };

      // 3. Call the feature service
      const result = await this.actionService.save(request);

      // 4. Post-save behavior
      if (this.isEditMode()) {
        await this.loadAction(this.id()!);
        this.toastr.success(await firstValueFrom(this.translate.get('common_save_success')));
      } else {
        this.toastr.success(await firstValueFrom(this.translate.get('common_create_success')));
        this.router.navigate(['/admin/actions', result.id]);
      }
    } catch (err: unknown) {
      const msg = (err as { error?: { errors?: { message?: string }[] } })
        ?.error?.errors?.[0]?.message
        ?? await firstValueFrom(this.translate.get('common_save_error'));
      this.errorMessage.set(msg);
      this.toastr.error(await firstValueFrom(this.translate.get('common_save_error')));
    } finally {
      this.saving.set(false);
    }
  }

  onCancel(): void {
    this.router.navigate(['/admin/actions']);
  }

  // --- Domain commands ---

  async onToggleStatus(): Promise<void> {
    const a = this.action();
    if (!a || a.isCore) return;

    const isActive = a.status.name === 'Active';
    const confirmed = await this.confirmService.confirm(
      await firstValueFrom(this.translate.get(
        isActive ? 'action_deactivate_confirm' : 'action_activate_confirm',
        { name: a.name },
      )),
      await firstValueFrom(this.translate.get('action_status_title')),
      {
        variant: isActive ? 'danger' : 'primary',
        confirmLabel: await firstValueFrom(
          this.translate.get(isActive ? 'common_deactivate' : 'common_activate'),
        ),
      },
    );
    if (!confirmed) return;

    try {
      const newStatus: EnumDTO = isActive
        ? { id: 1, name: 'Inactive' }
        : { id: 0, name: 'Active' };
      await this.actionService.updateStatus(a.id, { status: newStatus });
      await this.loadAction(a.id);
      this.toastr.success(await firstValueFrom(this.translate.get('action_status_success')));
    } catch {
      this.toastr.error(await firstValueFrom(this.translate.get('action_status_error')));
    }
  }

  // --- Helpers ---

  private generateSlug(name: string): string {
    return name
      .toLowerCase()
      .trim()
      .replace(/[^a-z0-9]+/g, '.')
      .replace(/^\.+|\.+$/g, '')
      .substring(0, 100);
  }
}

